patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -8,7 +8,7 @@
   output [7:0] mux_out
 );

-  always @(sel)
+  always @(sel or data_a or data_b or data_c or data_d)
   begin
     case(sel)
       2'b00: mux_out = data_a;

before_code:
module multiplexer_8bit(
  input [7:0] data_a,
  input [7:0] data_b,
  input [7:0] data_c,
  input [7:0] data_d,
  input [1:0] sel,
  output [7:0] mux_out
);

  always @(sel)
  begin
    case(sel)
      2'b00: mux_out = data_a;
      2'b01: mux_out = data_b;
      2'b10: mux_out = data_c;
      2'b11: mux_out = data_d;
      default: mux_out = 8'b0;
    endcase
  end

endmodule

after_code:
module multiplexer_8bit(
  input [7:0] data_a,
  input [7:0] data_b,
  input [7:0] data_c,
  input [7:0] data_d,
  input [1:0] sel,
  output [7:0] mux_out
);

  always @(sel or data_a or data_b or data_c or data_d)
  begin
    case(sel)
      2'b00: mux_out = data_a;
      2'b01: mux_out = data_b;
      2'b10: mux_out = data_c;
      2'b11: mux_out = data_d;
      default: mux_out = 8'b0;
    endcase
  end

endmodule
